+
+impl FieldMask {
+    const CONTENT: u8 = 1 << 0;
+    const SNIPPET: u8 = 1 << 1;
+    const TITLE: u8 = 1 << 2;
+    const CACHE: u8 = 1 << 3;
+
+    pub const FULL: Self = Self {
+        flags: Self::CONTENT | Self::SNIPPET | Self::TITLE | Self::CACHE,
+    };
+
+    pub fn new(
+        wants_content: bool,
+        wants_snippet: bool,
+        wants_title: bool,
+        allows_cache: bool,
+    ) -> Self {
+        let mut flags = 0;
+        if wants_content {
+            flags |= Self::CONTENT;
+        }
+        if wants_snippet {
+            flags |= Self::SNIPPET;
+        }
+        if wants_title {
+            flags |= Self::TITLE;
+        }
+        if allows_cache {
+            flags |= Self::CACHE;
+        }
+        Self { flags }
+    }
+
+    pub fn needs_content(self) -> bool {
+        self.flags & Self::CONTENT != 0
+    }
+
+    pub fn wants_snippet(self) -> bool {
+        self.flags & Self::SNIPPET != 0
+    }
+
+    pub fn wants_title(self) -> bool {
+        self.flags & Self::TITLE != 0
+    }
+
+    pub fn allows_cache(self) -> bool {
+        self.flags & Self::CACHE != 0
+    }
+}
